                    recovered.timestamp = (uint16_t)decrypted[1] | ((uint16_t)decrypted[2] << 8);
                    recovered.value = (int32_t)((uint32_t)decrypted[3] |
                                     ((uint32_t)decrypted[4] << 8) |
                                     ((uint32_t)decrypted[5] << 16) |
                                     ((uint32_t)decrypted[6] << 24));

                    printf("Sensor: type=%d, ts=%d, val=%d\n",
                           recovered.sensor_type, recovered.timestamp, (int)recovered.value);

